 // \u30e1\u30fc\u30bf\u30ea\u30f3\u30b0API\u3067\u3001\u30b3\u30e1\u30f3\u30c8\u6570\u306b\uff11\u3092\u8db3\u3059\n      let param: UpdateMeteringUnitTimestampCountNowParam = {\n        method: "add",\n        count: 1,\n      };\n      const res =\n        await pricingClient.meteringApi.updateMeteringUnitTimestampCountNow(\n          tenantId,\n          meteringUnitName,\n          param\n        );\n    }\n  } catch (error) {\n    console.error(error);\n  }\n  res.redirect("/chat");\n};\n'})})]})}function m(n={}){const{wrapper:t}={...(0,r.R)(),...n.components};return t?(0,a.jsx)(t,{...n,children:(0,a.jsx)(c,{...n})}):c(n)}}}]);